    /// <summary>
    /// Add logic to get the TPDimensionSetView DS otherwise
    /// We have an error on PurchTableListPageAssignedToMe form/Query
    /// </summary>
    /// <param name="args">QueryRun PurchTableListPageAssignedToMe</param>
    [PostHandlerFor(queryStr(PurchTableListPageAssignedToMe), queryMethodStr(PurchTableListPageAssignedToMe, init))]
    public static void PurchTableListPageAssignedToMe_Post_init(XppPrePostArgs args)
    {
        QueryBuildDataSource qbdsProjectDim, qbdsPurchSalesTable;

        QueryRun queryRun = args.getThis();
        Query    qr       = queryRun.query();

        qbdsProjectDim = qr.dataSourceTable(Tablenum(PurchTable)).addDataSource(tableNum(UBSPurchTableProjectDimensionView));
        qbdsProjectDim.joinMode(JoinMode::OuterJoin);
        qbdsProjectDim.relations(true);

        qbdsPurchSalesTable = qr.dataSourceTable(Tablenum(PurchTable)).addDataSource(tableNum(UBSPurchSalesTableLink));
        qbdsPurchSalesTable.joinMode(JoinMode::InnerJoin);
        qbdsPurchSalesTable.relations(true);
    }
